#include<bits/stdc++.h>
using namespace std;
long long s[100010],a[100010],sum[100010];
int n;
const long long mod=1e9+9;
int lowbit(int x)
{
    return x&-x;
}
void add(int x,int v)
{
    for(int i=x;i<=100005;i+=lowbit(i))
    {
        sum[i]+=v;
        sum[i]%=mod;
    }
}
long long query(int x)
{
    long long ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=sum[i];
        ans%=mod;
    }
    return ans;
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        a[i]+=a[i-1];
        s[i]=a[i];
    }
    sort(s+1,s+2+n);
    int m=unique(s+1,s+2+n)-s-1;
    for(int i=0;i<=n;i++)
    {
        a[i]=lower_bound(s+1,s+1+m,a[i])-s;
    }
    add(a[0],1);
    for(int i=1;i<=n;i++)
    {
        long long tmp=query(a[i]);
        add(a[i],tmp);
        if(i==n)
        {
            printf("%lld",tmp);
        }
    }
    return 0;
}
